CREATE TRIGGER LG_COSTDISTPEG_DEL_002_01 ON LG_002_01_COSTDISTPEG
FOR DELETE
AS
DECLARE @STTRANSREF INT
DECLARE @RECVSTTRANSREF INT
DECLARE @ADDEXPENSE FLOAT
DECLARE @ADDRPEXPENSE FLOAT
DECLARE @ADDEXPENSEUFRS FLOAT
DECLARE @ADDRPEXPENSEUFRS FLOAT
DECLARE @TRANTYPE  SMALLINT
DECLARE @PRDTRANSREF INT
SELECT @STTRANSREF = D.STTRANSREF,
       @RECVSTTRANSREF = D.RECVSTTRANSREF,
       @ADDEXPENSE    = D.ADDEXPENSE,
       @ADDRPEXPENSE    = D.ADDRPEXPENSE,
       @ADDEXPENSEUFRS    = D.ADDEXPENSEUFRS,
       @ADDRPEXPENSEUFRS  = D.ADDRPEXPENSEUFRS,
       @TRANTYPE = D.TRANTYPE,
      @PRDTRANSREF = D.PRDCOSTTRREF
       FROM DELETED D
EXECUTE LG_UPDATE_COSTPROC_002_01  @TRANTYPE, @STTRANSREF,@PRDTRANSREF, @RECVSTTRANSREF, @ADDEXPENSE, @ADDRPEXPENSE, @ADDEXPENSEUFRS, @ADDRPEXPENSEUFRS, -1
